import base64

content_base64 = ""

decoded = base64.b64decode(content_base64).decode('utf-8')
decoded = decoded.replace('%AKV_NAME%', '$AKV_NAME')
decoded = decoded.replace('%AKV_SECRET_NAME%', '$AKV_SECRET_NAME')
decoded = decoded.replace('%DB_PASSWORD%', '${DB_PASSWORD}')

with open('platform-infra/local-cluster.sh', 'w') as f:
    f.write(decoded)
